import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void classicPhrase() {
        assertTrue(new Solution().isValidPalindrome("A man, a plan, a canal: Panama"));
    }

    @Test
    void notPalindrome() {
        assertFalse(new Solution().isValidPalindrome("race a car"));
    }

    @Test
    void emptyString() {
        assertTrue(new Solution().isValidPalindrome(""));
    }

    @Test
    void onlyPunctuation() {
        assertTrue(new Solution().isValidPalindrome(".,;:!?"));
    }

    @Test
    void mixedAlphanumeric() {
        assertTrue(new Solution().isValidPalindrome("0P0"));
    }

    @Test
    void singleChar() {
        assertTrue(new Solution().isValidPalindrome("a"));
    }
}
